import{_ as e,o as a,c as l,a2 as r}from"./chunks/framework.BQ1gajhD.js";const f=JSON.parse('{"title":"东岳庙","description":"","frontmatter":{},"headers":[],"relativePath":"religion/dongyuemiao.md","filePath":"religion/dongyuemiao.md","lastUpdated":null}'),n={name:"religion/dongyuemiao.md"};function o(i,t,d,s,h,g){return a(),l("div",null,[...t[0]||(t[0]=[r('<h1 id="东岳庙" tabindex="-1">东岳庙 <a class="header-anchor" href="#东岳庙" aria-label="Permalink to &quot;东岳庙&quot;">​</a></h1><blockquote><p>&quot;北京最大的道教庙宇，七十六司神秘莫测。&quot;</p></blockquote><h2 id="简介" tabindex="-1">简介 <a class="header-anchor" href="#简介" aria-label="Permalink to &quot;简介&quot;">​</a></h2><p>东岳庙位于北京市朝阳区，是北京最大的道教庙宇，也是正一派在华北地区最大的庙宇。东岳庙始建于元代延祐六年（1319年），供奉东岳泰山神天齐仁圣大帝，主司人间生死祸福。</p><h2 id="基本信息" tabindex="-1">基本信息 <a class="header-anchor" href="#基本信息" aria-label="Permalink to &quot;基本信息&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">项目</th><th style="text-align:left;">内容</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>开放时间</strong></td><td style="text-align:left;">8:30-16:30</td></tr><tr><td style="text-align:left;"><strong>门票价格</strong></td><td style="text-align:left;">10元</td></tr><tr><td style="text-align:left;"><strong>建议游玩</strong></td><td style="text-align:left;">1-2小时</td></tr><tr><td style="text-align:left;"><strong>最佳季节</strong></td><td style="text-align:left;">春节庙会</td></tr><tr><td style="text-align:left;"><strong>交通方式</strong></td><td style="text-align:left;">地铁2号线/6号线朝阳门站</td></tr><tr><td style="text-align:left;"><strong>地址</strong></td><td style="text-align:left;">北京市朝阳区朝阳门外大街141号</td></tr></tbody></table><h2 id="历史沿革" tabindex="-1">历史沿革 <a class="header-anchor" href="#历史沿革" aria-label="Permalink to &quot;历史沿革&quot;">​</a></h2><h3 id="始建" tabindex="-1">始建 <a class="header-anchor" href="#始建" aria-label="Permalink to &quot;始建&quot;">​</a></h3><p>东岳庙始建于元延祐六年（1319年），由玄教大宗师张留孙及其弟子吴全节所建，供奉东岳泰山神。</p><h3 id="明清发展" tabindex="-1">明清发展 <a class="header-anchor" href="#明清发展" aria-label="Permalink to &quot;明清发展&quot;">​</a></h3><p>明代和清代，东岳庙多次扩建，规模不断扩大，成为北京最大的道教庙宇。</p><h3 id="现代" tabindex="-1">现代 <a class="header-anchor" href="#现代" aria-label="Permalink to &quot;现代&quot;">​</a></h3><p>1997年，东岳庙修复后对外开放。1999年，设立北京民俗博物馆。</p><h2 id="建筑布局" tabindex="-1">建筑布局 <a class="header-anchor" href="#建筑布局" aria-label="Permalink to &quot;建筑布局&quot;">​</a></h2><p>东岳庙规模宏大，占地约6万平方米，有房屋近400间。</p><h3 id="山门" tabindex="-1">山门 <a class="header-anchor" href="#山门" aria-label="Permalink to &quot;山门&quot;">​</a></h3><p>山门是东岳庙的入口，门额上书&quot;敕建东岳庙&quot;。</p><h3 id="瞻岱门" tabindex="-1">瞻岱门 <a class="header-anchor" href="#瞻岱门" aria-label="Permalink to &quot;瞻岱门&quot;">​</a></h3><p>瞻岱门是东岳庙的第二道门，&quot;岱&quot;指泰山。</p><h3 id="岱宗宝殿" tabindex="-1">岱宗宝殿 <a class="header-anchor" href="#岱宗宝殿" aria-label="Permalink to &quot;岱宗宝殿&quot;">​</a></h3><p>岱宗宝殿是东岳庙的主殿，供奉东岳泰山神天齐仁圣大帝。</p><h4 id="东岳大帝" tabindex="-1">东岳大帝 <a class="header-anchor" href="#东岳大帝" aria-label="Permalink to &quot;东岳大帝&quot;">​</a></h4><p>东岳大帝是道教尊神，掌管人间生死祸福，是阴间的最高统治者。</p><h3 id="七十六司" tabindex="-1">七十六司 <a class="header-anchor" href="#七十六司" aria-label="Permalink to &quot;七十六司&quot;">​</a></h3><p>七十六司是东岳庙的特色，是东岳大帝管辖的76个部门。</p><h4 id="各司职能" tabindex="-1">各司职能 <a class="header-anchor" href="#各司职能" aria-label="Permalink to &quot;各司职能&quot;">​</a></h4><table tabindex="0"><thead><tr><th style="text-align:left;">司</th><th style="text-align:left;">职能</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>生死司</strong></td><td style="text-align:left;">掌管生死</td></tr><tr><td style="text-align:left;"><strong>福禄司</strong></td><td style="text-align:left;">掌管福禄</td></tr><tr><td style="text-align:left;"><strong>善恶司</strong></td><td style="text-align:left;">掌管善恶</td></tr><tr><td style="text-align:left;"><strong>因果司</strong></td><td style="text-align:left;">掌管因果</td></tr><tr><td style="text-align:left;"><strong>速报司</strong></td><td style="text-align:left;">掌管报应</td></tr><tr><td style="text-align:left;"><strong>地狱司</strong></td><td style="text-align:left;">掌管地狱</td></tr></tbody></table><p>七十六司塑像神态各异，非常逼真，体现了民间对阴间的想象。</p><h3 id="碑林" tabindex="-1">碑林 <a class="header-anchor" href="#碑林" aria-label="Permalink to &quot;碑林&quot;">​</a></h3><p>东岳庙内有大量碑刻，是研究道教和民俗的重要资料。</p><h2 id="北京民俗博物馆" tabindex="-1">北京民俗博物馆 <a class="header-anchor" href="#北京民俗博物馆" aria-label="Permalink to &quot;北京民俗博物馆&quot;">​</a></h2><p>东岳庙内设有北京民俗博物馆，展示北京的民俗文化。</p><h3 id="展览内容" tabindex="-1">展览内容 <a class="header-anchor" href="#展览内容" aria-label="Permalink to &quot;展览内容&quot;">​</a></h3><ul><li><strong>老北京生活</strong>：老北京的衣食住行</li><li><strong>老北京节庆</strong>：春节、中秋等传统节日</li><li><strong>老北京行业</strong>：各行各业的民俗</li><li><strong>老北京信仰</strong>：民间信仰</li></ul><h2 id="春节庙会" tabindex="-1">春节庙会 <a class="header-anchor" href="#春节庙会" aria-label="Permalink to &quot;春节庙会&quot;">​</a></h2><p>东岳庙每年春节举办庙会，是北京著名的庙会之一。</p><h3 id="庙会时间" tabindex="-1">庙会时间 <a class="header-anchor" href="#庙会时间" aria-label="Permalink to &quot;庙会时间&quot;">​</a></h3><p>每年春节期间，正月初一至十五。</p><h3 id="庙会内容" tabindex="-1">庙会内容 <a class="header-anchor" href="#庙会内容" aria-label="Permalink to &quot;庙会内容&quot;">​</a></h3><ul><li><strong>祈福法会</strong>：道教祈福仪式</li><li><strong>民俗表演</strong>：舞狮、高跷等</li><li><strong>民间手工艺</strong>：面人、糖人等</li><li><strong>传统小吃</strong>：各种传统小吃</li></ul><h2 id="游览攻略" tabindex="-1">游览攻略 <a class="header-anchor" href="#游览攻略" aria-label="Permalink to &quot;游览攻略&quot;">​</a></h2><h3 id="推荐路线" tabindex="-1">推荐路线 <a class="header-anchor" href="#推荐路线" aria-label="Permalink to &quot;推荐路线&quot;">​</a></h3><p><strong>经典路线（约1-2小时）</strong>：</p><p>山门 → 瞻岱门 → 岱宗宝殿 → 七十六司 → 碑林 → 民俗博物馆 → 出庙</p><h3 id="交通方式" tabindex="-1">交通方式 <a class="header-anchor" href="#交通方式" aria-label="Permalink to &quot;交通方式&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">方式</th><th style="text-align:left;">站点</th></tr></thead><tbody><tr><td style="text-align:left;">地铁</td><td style="text-align:left;">2号线/6号线朝阳门站A口</td></tr><tr><td style="text-align:left;">公交</td><td style="text-align:left;">101路、109路、110路等朝阳门外站</td></tr><tr><td style="text-align:left;">步行</td><td style="text-align:left;">从东四步行约15分钟</td></tr></tbody></table><h3 id="实用贴士" tabindex="-1">实用贴士 <a class="header-anchor" href="#实用贴士" aria-label="Permalink to &quot;实用贴士&quot;">​</a></h3><ol><li><strong>门票便宜</strong>：门票仅10元</li><li><strong>七十六司必看</strong>：七十六司是精华，必看</li><li><strong>春节庙会</strong>：春节庙会热闹</li><li><strong>民俗博物馆</strong>：了解老北京民俗</li><li><strong>保持敬畏</strong>：七十六司有些阴森，保持敬畏</li><li><strong>结合游览</strong>：可与朝阳门外商圈一起游览</li></ol><h2 id="周边景点" tabindex="-1">周边景点 <a class="header-anchor" href="#周边景点" aria-label="Permalink to &quot;周边景点&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">景点</th><th style="text-align:center;">距离</th><th style="text-align:left;">特色</th></tr></thead><tbody><tr><td style="text-align:left;">朝阳门外商圈</td><td style="text-align:center;">紧邻</td><td style="text-align:left;">商业区</td></tr><tr><td style="text-align:left;">三里屯</td><td style="text-align:center;">地铁2站</td><td style="text-align:left;">时尚商业区</td></tr><tr><td style="text-align:left;">工体</td><td style="text-align:center;">步行15分钟</td><td style="text-align:left;">体育场馆</td></tr><tr><td style="text-align:left;">日坛公园</td><td style="text-align:center;">步行20分钟</td><td style="text-align:left;">明清祭日之所</td></tr></tbody></table><h2 id="文化价值" tabindex="-1">文化价值 <a class="header-anchor" href="#文化价值" aria-label="Permalink to &quot;文化价值&quot;">​</a></h2><p>东岳庙是北京最大的道教庙宇，是研究道教和民俗的重要场所。</p><p>东岳庙的七十六司是民间信仰的重要体现，反映了民间对生死、善恶的认识。</p><p>东岳庙的春节庙会是北京传统民俗的重要组成部分。</p><hr><p><strong>📍 地址</strong>：北京市朝阳区朝阳门外大街141号 <strong>📞 电话</strong>：010-65510151</p>',56)])])}const b=e(n,[["render",o]]);export{f as __pageData,b as default};
